import { PosInfo } from './type';

export const domBreakingAutoReporting = (error: Error, pos?: PosInfo) => {
    window?.__OSS_MONITOR_SDK_?.error(
        {
            name: error.name,
            message: `React Dom Breaking_Auto Reporting:${error.message}`,
            stack: error.stack
        },
        pos
    );
};
